#include <stdlib.mqh>
#include <stderror.mqh>

// Dichiarazione delle variabili esterne
extern double Lots = 1; // Dimensione del lotto standard

// Controllo del profitto
extern double StopLoss = 150; // Massimo pip disposti a perdere per posizione
extern bool UseTrailingStop = true; // Se utilizzare Trailing Stop
extern int TrailingStopType = 2; // Tipo di Trailing Stop (1 immediato, 2 attesa)
extern double TrailingStop = 25; // Numero di pips per il trailing stop
extern bool UseTakeProfit = true; // Se utilizzare Take Profit
extern int TakeProfit = 300; // Massimo livello di profitto raggiungibile
extern int Slippage = 3; // Slittamento possibile

bool h4ConditionMet = false;
bool stochOpenCondition = false; // Per gestire il flag di apertura basato sull’indicatore stocastico
static datetime lastH4BarTime = 0;
bool isNewH4Bar = false;
bool stochConditionMet = false;

// Intestazioni di etichettatura trade
string label = "== scegli 15, 30, 60, 240 (4 ore) per timeframe di uscita";
extern int exittimeframe = 30; // Timeframe di uscita

// Variabili interne
bool isTradeOpened = false; // Variabile per tenere traccia se abbiamo già aperto un trade per il segnale corrente

double lowlimit = 20;
double highlimit = 80;
double myStopLoss;
double lotMM;
int MagicNumber;
string setup = "";

// Riprova impostazioni
int totalTries = 5;
int retryDelay = 1000;

// Debugging
bool Debug=false;

//±-----------------------------------------------------------------+
//| Funzione di init() |
//±-----------------------------------------------------------------+
int init() {
MagicNumber = 5000 + Symbol2Val(Symbol()) * 100 + TimeFrame_Const2Val(Period());
setup = "Stoch 5 EA " + Symbol() + "_" + TimeFrame_Val2String(TimeFrame_Const2Val(Period()));
return(0);
}

//±-----------------------------------------------------------------+
//| Funzione di deinit() |
//±-----------------------------------------------------------------+
int deinit() {
// Qui potresti implementare la pulizia delle risorse se necessario
return(0);
}

//NormalizeDouble
double NormalizePrice(double price) {
return(NormalizeDouble(price, Digits));
}

double GetMinStopLoss(double price, bool isBuy) {
double minStopLevel = MarketInfo(Symbol(), MODE_STOPLEVEL) * Point;
if (isBuy) {
// Per ordini di acquisto, lo stop loss non può essere inferiore al prezzo corrente più il minStopLevel
return(NormalizePrice(price + minStopLevel));
} else {
// Per ordini di vendita, lo stop loss non può essere maggiore del prezzo corrente meno il minStopLevel
return(NormalizePrice(price - minStopLevel));
}
}

//±-----------------------------------------------------------------+
//| Controlla le posizioni aperte |
//±-----------------------------------------------------------------+
int CheckOpenPositions() {
int NumBuyTrades = 0, NumSellTrades = 0;
for (int i = 0; i < OrdersTotal(); i++) {
if (!OrderSelect(i, SELECT_BY_POS, MODE_TRADES) ||
OrderSymbol() != Symbol() ||
OrderMagicNumber() != MagicNumber) continue;

if (OrderType() == OP_BUY) NumBuyTrades++;
if (OrderType() == OP_SELL) NumSellTrades++;
}
return (NumBuyTrades + NumSellTrades);
}

//±-----------------------------------------------------------------+
//| Funzione start() |
//±-----------------------------------------------------------------+
int start() {
    Print("Inizio esecuzione di ‘start()’"); // Stampa di controllo
    BeginHandleStopLoss();
    HandleOpenPositions();

    if (NewBarH4()) {
        if (CheckOpenPositions() == 0) {
            Print("Rilevata una nuova barra H4. Risettiamo le condizioni necessarie.");
            h4ConditionMet = false; // Reset di h4ConditionMet all’inizio di una nuova barra H4 e nessun trade aperto
        }
    }

    if (!h4ConditionMet && CheckOpenPositions() == 0) {
        if (BuySignal()) {
            Print("Verificata condizione di Buy.");
            if (OpenBuyOrder()) {
                Print("Aperto ordine Buy.");
                h4ConditionMet = true; // Un trade è stato aperto, quindi impostiamo h4ConditionMet su true
            } else {
                Print("Ordine Buy non aperto.");
            }
        } else if (SellSignal()) {
            Print("Verificata condizione di Sell.");
            if (OpenSellOrder()) {
                Print("Aperto ordine Sell.");
                h4ConditionMet = true; // Un trade è stato aperto, quindi impostiamo h4ConditionMet su true
            } else {
                Print("Ordine Sell non aperto.");
            }
        } else {
            Print("Nessuna condizione di Buy o Sell soddisfatta.");
        }
    } else {
        if (h4ConditionMet) {
            Print("Un trade è già stato aperto nell’attuale barra H4, aspettiamo la prossima barra.");
        } else {
            Print("Ci sono già posizioni aperte o in attesa.");
        }
    }

    return(0); // Fine della funzione start()
}

//±-----------------------------------------------------------------+
//| Gestisce il trailing stop per tutte le posizioni |
//±-----------------------------------------------------------------+
int BeginHandleStopLoss() {
for (int cnt = OrdersTotal() - 1; cnt >= 0; cnt--) {
if (!OrderSelect(cnt, SELECT_BY_POS, MODE_TRADES)) continue;
if (OrderSymbol() != Symbol() || OrderMagicNumber() != MagicNumber) continue;

if (OrderType() == OP_BUY || OrderType() == OP_SELL) {
if (UseTrailingStop) {
HandleTrailingStop(OrderType(),OrderTicket(),OrderOpenPrice(),OrderStopLoss(),OrderTakeProfit());
}
}
}
return(0);
}

//±-----------------------------------------------------------------+
//| Segnale di acquisto tramite analisi dello stocastico |
//±-----------------------------------------------------------------+
bool BuySignal() {
    if (!h4ConditionMet && isNewH4Bar && StochOpen("Long")) {
        return true;
    }
    return false;
}

//±-----------------------------------------------------------------+
//| Segnale di vendita tramite analisi dello stocastico |
//±-----------------------------------------------------------------+
bool SellSignal() {
    if (!h4ConditionMet && isNewH4Bar && StochOpen("Short")) {
        return true;
    }
    return false;
}

//±-----------------------------------------------------------------+
//| Apertura di un ordine di acquisto |
//±-----------------------------------------------------------------+
bool OpenBuyOrder() {
    if (isTradeOpened) return false; // Verifica se un’operazione è già in corso

    double ask = MarketInfo(Symbol(), MODE_ASK);
    double slippagePoints = Slippage * Point;
    double stopBuffer = 2 * MarketInfo(Symbol(), MODE_STOPLEVEL) * Point;
    double myStopLoss = NormalizeDouble(ask - StopLoss * Point - stopBuffer, Digits);

    double myTakeProfit = 0;
    if (UseTakeProfit && TakeProfit > 0) {
        myTakeProfit = NormalizeDouble(ask + TakeProfit * Point, Digits);
    }

    int ticket = OrderSend(Symbol(), OP_BUY, Lots, ask, Slippage, myStopLoss, myTakeProfit, setup, MagicNumber, 0, clrGreen);
    if (ticket < 0) {
        Print("Error Opening BUY Order: ", GetLastError());
        return false; // La funzione ritorna false perché l’ordine non è stato aperto
    }

    isTradeOpened = true; // Segnala che un trade è stato aperto
    return true; // La funzione ritorna true perché l’ordine è stato aperto con successo
}

bool OpenSellOrder() {
    if (isTradeOpened) return false; // Verifica se un’operazione è già in corso

    double bid = MarketInfo(Symbol(), MODE_BID);
    double slippagePoints = Slippage * Point;
    double stopBuffer = 2 * MarketInfo(Symbol(), MODE_STOPLEVEL) * Point;
    double myStopLoss = NormalizeDouble(bid + StopLoss * Point + stopBuffer, Digits);

    double myTakeProfit = 0;
    if (UseTakeProfit && TakeProfit > 0) {
        myTakeProfit = NormalizeDouble(bid - TakeProfit * Point, Digits);
    }

    int ticket = OrderSend(Symbol(), OP_SELL, Lots, bid, Slippage, myStopLoss, myTakeProfit, setup, MagicNumber, 0, clrRed);
    if (ticket < 0) {
        Print("Error Opening SELL Order: ", GetLastError());
        return false; // La funzione ritorna false perché l’ordine non è stato aperto
    }

    isTradeOpened = true; // Segnala che un trade è stato aperto
    return true; // La funzione ritorna true perché l’ordine è stato aperto con successo
}
//±-----------------------------------------------------------------+
//| Analisi Stocastica per i segnali di apertura ordini |
//±-----------------------------------------------------------------+
bool StochOpen(string signal) {
        Print("StochOpen() called for ", signal);
    // Solo se siamo all’inizio di una nuova barra H4 determiniamo se il segnale principale è attivo
    if (NewBarH4()) {
        // Calcolo dello Stocastico per H4 utilizzando la barra PRECEDENTE appena chiusa
        double main_4H = iStochastic(NULL, PERIOD_H4, 5, 3, 3, MODE_SMA, 1, MODE_MAIN, 0); // Barra chiusa
         Print("Stochastic H4 value: ", main_4H);
        // Se lo stocastico ha incrociato il limite stabilito e non abbiamo ancora segnalato l’evento
        if ((signal == "Long" && main_4H >= lowlimit && !stochConditionMet) ||
            (signal == "Short" && main_4H <= highlimit && !stochConditionMet)) {
            // Ora verifichiamo se il segnale sugli altri timeframe corrisponde
            if (CheckOtherTimeframes(signal)) {
                stochConditionMet = true; // Segnala che abbiamo un segnale valido
                return true;
            }
        }
    }

    // Se non ci troviamo in una nuova barra H4, o il segnale non è stato confermato sugli altri timeframe, ritorniamo false
    return false;
}

// Funzione per verificare il segnale sugli altri timeframe
bool CheckOtherTimeframes(string signal) {
    Print("CheckOtherTimeframes() called for ", signal);
    double main_15 = iStochastic(NULL, PERIOD_M15, 5, 3, 3, MODE_SMA, 0, MODE_MAIN, 0);
    double main_30 = iStochastic(NULL, PERIOD_M30, 5, 3, 3, MODE_SMA, 0, MODE_MAIN, 0);
    double main_1H = iStochastic(NULL, PERIOD_H1, 5, 3, 3, MODE_SMA, 0, MODE_MAIN, 0);

    if (signal == "Long" && main_15 >= lowlimit && main_30 >= lowlimit && main_1H >= lowlimit) {
        Print("Buy conditions met on M15, M30, and H1.");
        return true;
    } else if (signal == "Short" && main_15 <= highlimit && main_30 <= highlimit && main_1H <= highlimit) {
        Print("Sell conditions met on M15, M30, and H1.");
        return true;
    }

    Print("Conditions not met on other timeframes for ", signal);
    return false;
}

//±-----------------------------------------------------------------+
//| Rileva la nuova barra del timeframe H4 |
//±-----------------------------------------------------------------+
bool NewBarH4() {
    datetime currentH4BarTime = iTime(Symbol(), PERIOD_H4, 0);
    if (currentH4BarTime != lastH4BarTime) {
        lastH4BarTime = currentH4BarTime;
        stochOpenCondition = false; // Reset delle condizioni
        Print("New H4 bar detected at ", TimeToString(currentH4BarTime));
        return true;
    }
    return false;
}
