    HandleOpenPositions(); // Gestione delle posizioni aperte

    // Verifica se siamo all’inizio di una nuova barra H4
    isNewH4Bar = NewBarH4();

    if (isNewH4Bar) {
        if (CheckOpenPositions() == 0) {
            stochConditionMet = false; // Resetta la condizione Stochastic se non ci sono posizioni aperte
            Print("Nuova barra H4 e nessuna posizione aperta. Reset del flag stochConditionMet.");
        }
        Print("Rilevata una nuova barra H4. Verifica per la possibilità di un nuovo trade.");
    }

    // Verifica per l’apertura delle posizioni solo se non abbiamo posizioni per il segnale corrente
    if (!stochConditionMet && CheckOpenPositions() == 0) {
        if (BuySignal()) {
            Print("Verificata condizione di Buy.");
            if (OpenBuyOrder()) {
                Print("Aperto ordine Buy.");
                stochConditionMet = true;
            } else {
                Print("Ordine Buy non aperto. Errore: ", GetLastError());
            }
        } else if (SellSignal()) {
            Print("Verificata condizione di Sell.");
            if (OpenSellOrder()) {
                Print("Aperto ordine Sell.");
                stochConditionMet = true;
            } else {
                Print("Ordine Sell non aperto. Errore: ", GetLastError());
            }
        } else {
            Print("Nessuna condizione di Buy o Sell soddisfatta al momento.");
        }
    } else {
        if (stochConditionMet) {
            Print("Condizioni dello Stochastic già state soddisfatte, in attesa di una nuova barra H4.");
        } else {
            Print("Ci sono già posizioni aperte o in attesa.");
        }
    }

    return(0); // Fine della funzione start()
}

