bool CheckOtherTimeframes(string signal, int timeframeIndex) {
    int timeframePeriod = TimeFrame_Const2Val(timeframeIndex); // Ottiene il periodo per il timeframe

    // Calcola il valore dello stocastico per il timeframe corrente
    double curr_main = iStochastic(NULL, timeframePeriod, 5, 3, 3, MODE_SMA, 1, MODE_MAIN, 0);
    double prev_main = iStochastic(NULL, timeframePeriod, 5, 3, 3, MODE_SMA, 1, MODE_MAIN, 1);

