double ValidStopLoss(int tradeType, double proposedStop) {
double minStopLevel = MarketInfo(Symbol(), MODE_STOPLEVEL) * MarketInfo(Symbol(), MODE_POINT);

// Ajusta lo stop loss proposto a seconda se è BUY o SELL
if (tradeType == OP_BUY && proposedStop < Ask - minStopLevel) {
return (Ask - minStopLevel);
} else if (tradeType == OP_SELL && proposedStop > Bid + minStopLevel) {
return (Bid + minStopLevel);
}
return(proposedStop);
}
