    if (TP_StochCross == 1) {
        double stoch_main = iStochastic(NULL, M30, 5, 3, 3, MODE_SMA, 1, MODE_MAIN, 0);
        double stoch_signal = iStochastic(NULL, M30, 5, 3, 3, MODE_SMA, 1, MODE_SIGNAL, 0);

        // Se lo stocastico principale è sotto il segnale (potenziale segnale di oversold), impostiamo il TP
        if (stoch_main < stoch_signal) {
            myTakeProfit = bid + (stoch_signal - stoch_main) * Point; // Calcoliamo il TP in base alla differenza tra i valori stocastici
            myTakeProfit = NormalizePrice(myTakeProfit);
        }
    }

    //... (resto del codice per inviare l'ordine SELL)
}

