void HandleTrailingStop(int tradeType, int ticket, double openPrice, double currentStop, double currentTP) {
double point = MarketInfo(Symbol(), MODE_POINT);
double newStop;

if (tradeType == OP_BUY) {
double buyTrailStopLevel = openPrice + TrailingStop * point;
if (Bid >= buyTrailStopLevel) {
newStop = Bid - TrailingStop * point;
newStop = NormalizeDouble(newStop, Digits);
if (newStop != currentStop) {
OrderModify(ticket, openPrice, newStop, currentTP, 0, clrNONE);
if (Debug) Print("Modificato il Trailing Stop BUY per il ticket ", ticket);
}
}
} else if (tradeType == OP_SELL) {
double sellTrailStopLevel = openPrice - TrailingStop * point;
if (Ask <= sellTrailStopLevel) {
newStop = Ask + TrailingStop * point;
newStop = NormalizeDouble(newStop, Digits);
if (newStop != currentStop) {
OrderModify(ticket, openPrice, newStop, currentTP, 0, clrNONE);
if (Debug) Print("Modificato il Trailing Stop SELL per il ticket ", ticket);
}
}
}
}

