//| Apertura di un ordine di acquisto |
//±-----------------------------------------------------------------+
bool OpenBuyOrder() {
    if (isTradeOpened) return false;  // Verifica se un’operazione è già in corso

    double ask = MarketInfo(Symbol(), MODE_ASK);
    double slippagePoints = Slippage * Point;
    double stopBuffer = 2 * MarketInfo(Symbol(), MODE_STOPLEVEL) * Point;
    double myStopLoss = NormalizePrice(ask - StopLoss * Point - stopBuffer);

    double myTakeProfit = 0;
    if (UseTakeProfit) {
        myTakeProfit = NormalizePrice(ask + TakeProfit * Point);  // Imposta un take profit fisso
    }

    int ticket = OrderSend(Symbol(), OP_BUY, Lots, ask, Slippage, myStopLoss, myTakeProfit, setup, MagicNumber, 0, clrGreen);
    if (ticket < 0) {
        Print("Errore nell’apertura dell’ordine BUY: ", GetLastError());
        return false;
    }

    if (UseTakeProfit && TP_StochCross == 1) {
        // Calcola il TP dinamico basato sull’incrocio dello stocastico M30
        double stoch_main = iStochastic(NULL, PERIOD_M30, 5, 3, 3, MODE_SMA, 1, MODE_MAIN, 0);
        double stoch_signal = iStochastic(NULL, PERIOD_M30, 5, 3, 3, MODE_SMA, 1, MODE_SIGNAL, 0);
        if (stoch_main > stoch_signal) {
            // Se il valore della linea principale dello stocastico è superiore a quello del segnale, impostiamo un TP più cauto
            double stoch_diff = (stoch_main - stoch_signal) * Point;  // calcola la differenza in punti
            myTakeProfit = NormalizePrice(ask + stoch_diff);
            // Aggiorna l’ordine con il nuovo TP
            bool result = OrderModify(ticket, OrderOpenPrice(), OrderStopLoss(), myTakeProfit, 0, clrGreen);
            if (!result) {
                Print("Errore nell’aggiornamento dell’ordine BUY con il TP dinamico: ", GetLastError());
            }
        }
    }

    isTradeOpened = true;
    return true;
}

bool OpenSellOrder() {
    if (isTradeOpened) return false;  // Verifica se un’operazione è già in corso

    double bid = MarketInfo(Symbol(), MODE_BID);
    double slippagePoints = Slippage * Point;
    double stopBuffer = 2 * MarketInfo(Symbol(), MODE_STOPLEVEL) * Point;
    double myStopLoss = NormalizePrice(bid + StopLoss * Point + stopBuffer);

    double myTakeProfit = 0;
    if (UseTakeProfit) {
        myTakeProfit = NormalizePrice(bid - TakeProfit * Point);  // Imposta un take profit fisso
    }

    int ticket = OrderSend(Symbol(), OP_SELL, Lots, bid, Slippage, myStopLoss, myTakeProfit, setup, MagicNumber, 0, clrRed);
    if (ticket < 0) {
        Print("Errore nell’apertura dell’ordine SELL: ", GetLastError());
        return false;
    }

    if (UseTakeProfit && TP_StochCross == 1) {
        // Calcola il TP dinamico basato sull’incrocio dello stocastico M30
        double stoch_main = iStochastic(NULL, PERIOD_M30, 5, 3, 3, MODE_SMA, 1, MODE_MAIN, 0);
        double stoch_signal = iStochastic(NULL, PERIOD_M30, 5, 3, 3, MODE_SMA, 1, MODE_SIGNAL, 0);
        if (stoch_main < stoch_signal) {
            // Se il valore della linea principale dello stocastico è inferiore a quello del segnale, impostiamo un TP più cauto
            double stoch_diff = (stoch_signal - stoch_main) * Point;  // calcola la differenza in punti
            myTakeProfit = NormalizePrice(bid - stoch_diff);
            // Aggiorna l’ordine con il nuovo TP
            bool result = OrderModify(ticket, OrderOpenPrice(), OrderStopLoss(), myTakeProfit, 0, clrRed);
            if (!result) {
                Print("Errore nell’aggiornamento dell’ordine SELL con il TP dinamico: ", GetLastError());
            }
        }
    }

    isTradeOpened = true;
    return true;
}
