    double prev_main_4H = iStochastic(NULL, PERIOD_H4, 5, 3, 3, MODE_SMA, 1, MODE_MAIN, 1);

    // Verifica che la direzione dello stocastico sia consistente con il segnale richiesto
    if ((signal == "Long" && curr_main_4H > prev_main_4H && curr_main_4H >= lowlimit) ||
        (signal == "Short" && curr_main_4H < prev_main_4H && curr_main_4H <= highlimit)) {

        // Verifica su M15
        double curr_main_M15 = iStochastic(NULL, PERIOD_M15, 5, 3, 3, MODE_SMA, 1, MODE_MAIN, 0);
        double prev_main_M15 = iStochastic(NULL, PERIOD_M15, 5, 3, 3, MODE_SMA, 1, MODE_MAIN, 1);

        // Verifica su M30
        double curr_main_M30 = iStochastic(NULL, PERIOD_M30, 5, 3, 3, MODE_SMA, 1, MODE_MAIN, 0);
        double prev_main_M30 = iStochastic(NULL, PERIOD_M30, 5, 3, 3, MODE_SMA, 1, MODE_MAIN, 1);

        // Verifica su H1
        double curr_main_H1 = iStochastic(NULL, PERIOD_H1, 5, 3, 3, MODE_SMA, 1, MODE_MAIN, 0);
        double prev_main_H1 = iStochastic(NULL, PERIOD_H1, 5, 3, 3, MODE_SMA, 1, MODE_MAIN, 1);

        // Verifica che la direzione sia confermata su tutti i timeframe
        if ((signal == "Long" && 
             curr_main_M15 > prev_main_M15 && curr_main_M15 > lowlimit &&
             curr_main_M30 > prev_main_M30 && curr_main_M30 > lowlimit &&
             curr_main_H1 > prev_main_H1 && curr_main_H1 > lowlimit) ||
            (signal == "Short" && 
             curr_main_M15 < prev_main_M15 && curr_main_M15 < highlimit &&
             curr_main_M30 < prev_main_M30 && curr_main_M30 < highlimit &&
             curr_main_H1 < prev_main_H1 && curr_main_H1 < highlimit)) {

            stochConditionMet = true; // Conferma che abbiamo un segnale valido
            Print("Condizione dello stocastico H4 e condizioni su altri timeframe soddisfatte per ", signal);
            return true;
        }
    }

    Print("Condizioni per ", signal, " non soddisfatte o nessuna nuova barra H4.");
    return false;
}

