            double newSL = NormalizePrice(ask - stoch_diff);

            // Verifica che il nuovo SL non sia troppo vicino al prezzo corrente, maggiore del minimo stopLevel
            double minStopDistance = MarketInfo(Symbol(), MODE_STOPLEVEL) * Point;
            newSL = MathMax(newSL, ask + minStopDistance);

            // Modifica l'ordine per aggiornare lo SL
